# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.tactics.try_refl","kind":"function","src_hash":"88bb35ecfeb1fe4f","in":{"base":"OTerm"},"out":{"base":"TacticResult"},"spec":{"lhs":"try_refl(lhs)","rhs":"try to close the goal by reflexivity","over":{"base":"OTerm"},"name":"try_refl_correct","kind":"composition"},"guarantee":"try to close the goal by reflexivity","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"TacticResult","by":"library_axiom"},{"fn":"Refl","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"7a13ab5ab595de95"}
def try_refl(lhs: OTerm, rhs: OTerm) -> TacticResult:
    """Try to close the goal by reflexivity.

    Succeeds if lhs and rhs are syntactically equal (up to
    normalization).
    """
    if terms_equal(lhs, rhs):
        return TacticResult(Refl(lhs), 'refl')

    n_lhs = normalize_term(lhs)
    n_rhs = normalize_term(rhs)
    if terms_equal(n_lhs, n_rhs):
        return TacticResult(Refl(n_lhs), 'refl (normalized)')

    if lhs.canon() == rhs.canon():
        return TacticResult(Refl(lhs), 'refl (canon)')

    return TacticResult(None, 'not reflexive')


