# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.tactics.try_assumption","kind":"function","src_hash":"89b3e5ecda96004e","in":{"base":"OTerm"},"out":{"base":"TacticResult"},"spec":{"lhs":"try_assumption(lhs)","rhs":"try to close the goal using an assumption from the context","over":{"base":"OTerm"},"name":"try_assumption_correct"},"guarantee":"try to close the goal using an assumption from the context","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.tactics.try_assumption_correct","statement":"Path(try_assumption(x), try to close the goal using an assumption from the context)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"643d87ee070c987b"}
def try_assumption(lhs: OTerm, rhs: OTerm,
                   ctx: ProofContext) -> TacticResult:
    """Try to close the goal using an assumption from the context."""
    for label, (a_lhs, a_rhs) in ctx.assumptions.items():
        if terms_equal(lhs, a_lhs) and terms_equal(rhs, a_rhs):
            return TacticResult(
                Assume(label, a_lhs, a_rhs),
                f'assumption {label}'
            )
        n_lhs = normalize_term(lhs)
        n_rhs = normalize_term(rhs)
        n_a_lhs = normalize_term(a_lhs)
        n_a_rhs = normalize_term(a_rhs)
        if terms_equal(n_lhs, n_a_lhs) and terms_equal(n_rhs, n_a_rhs):
            return TacticResult(
                Assume(label, a_lhs, a_rhs),
                f'assumption {label} (normalized)'
            )
    return TacticResult(None, 'no matching assumption')


