# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.tactics.simp","kind":"function","src_hash":"7eb526cc75d845b3","in":{"base":"OTerm"},"out":{"base":"TacticResult"},"spec":{"lhs":"simp(lhs)","rhs":"simplification tactic \u2014 apply simplification rules exhaustively","over":{"base":"OTerm"},"name":"simp_correct"},"guarantee":"simplification tactic \u2014 apply simplification rules exhaustively","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.tactics.simp_correct","statement":"Path(simp(x), simplification tactic \u2014 apply simplification rules exhaustively)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"17b68d194b3b75e7"}
def simp(lhs: OTerm, rhs: OTerm,
         axioms: Optional[List[str]] = None) -> TacticResult:
    """Simplification tactic — apply simplification rules exhaustively.

    Tries to normalize both sides and check equality.  If axioms are
    given, applies them as rewrite rules.
    """
    # Step 1: try reflexivity
    r = try_refl(lhs, rhs)
    if r.success:
        return r

    # Step 2: try arithmetic simplification
    r = try_arith(lhs, rhs)
    if r.success:
        return r

    # Step 3: try normalizing both sides
    n_lhs = normalize_term(lhs)
    n_rhs = normalize_term(rhs)
    if terms_equal(n_lhs, n_rhs):
        return TacticResult(Definitional(), 'simp (normalized)')

    # Step 4: if axioms given, try each one
    if axioms:
        for axiom_name in axioms:
            r = try_axiom_rewrite(lhs, rhs, axiom_name)
            if r.success:
                return r

    return TacticResult(None, 'simp: could not simplify')


