# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.tactics.unfold","kind":"function","src_hash":"b143c0ca7787727c","in":{"base":"OTerm","pred":"isinstance(lhs, OOp)"},"out":{"base":"TacticResult"},"spec":{"lhs":"unfold(lhs)","rhs":"unfold a function definition","over":{"base":"OTerm","pred":"isinstance(lhs, OOp)"},"name":"unfold_correct"},"guarantee":"unfold a function definition","fibers":[{"name":"OOp","pred":"isinstance(lhs, OOp)","path":{"lhs":"unfold(x)","rhs":"unfold a function definition","over":{"base":"OOp","pred":"isinstance(lhs, OOp)"},"name":"unfold_OOp_case"},"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.tactics.unfold_OOp_correct","statement":"unfold satisfies spec on OOp inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":1,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"bd4bad960d21f8f7"}
def unfold(lhs: OTerm, rhs: OTerm, func_name: str,
           ctx: Optional[ProofContext] = None) -> TacticResult:
    """Unfold a function definition.

    If lhs is f(args), produces Delta(f, args) proving
    f(args) ≡ body[params:=args].
    """
    if isinstance(lhs, OOp) and lhs.name == func_name:
        proof = Delta(func_name, tuple(lhs.args))
        return TacticResult(proof, f'unfold {func_name}')

    if isinstance(rhs, OOp) and rhs.name == func_name:
        proof = Sym(Delta(func_name, tuple(rhs.args)))
        return TacticResult(proof, f'fold {func_name}')

    return TacticResult(None, f'unfold: {func_name} not found in goal')


