# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.tactics.try_axiom_rewrite","kind":"function","src_hash":"fce67ee4c3512ed0","in":{"base":"OTerm"},"out":{"base":"TacticResult"},"spec":{"lhs":"try_axiom_rewrite(lhs)","rhs":"try to apply a cctt axiom as a rewrite","over":{"base":"OTerm"},"name":"try_axiom_rewrite_correct"},"guarantee":"try to apply a cctt axiom as a rewrite","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.tactics.try_axiom_rewrite_correct","statement":"Path(try_axiom_rewrite(x), try to apply a cctt axiom as a rewrite)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"2ae026e8720d580b"}
def try_axiom_rewrite(lhs: OTerm, rhs: OTerm,
                      axiom_name: str) -> TacticResult:
    """Try to apply a CCTT axiom as a rewrite."""
    # Try forward
    proof_fwd = AxiomApp(axiom_name, 'forward', lhs)
    r = check_proof(proof_fwd, lhs, rhs)
    if r.valid:
        return TacticResult(proof_fwd, f'axiom {axiom_name} →')

    # Try backward
    proof_bwd = AxiomApp(axiom_name, 'backward', rhs)
    r = check_proof(proof_bwd, lhs, rhs)
    if r.valid:
        return TacticResult(proof_bwd, f'axiom {axiom_name} ←')

    return TacticResult(None, f'axiom {axiom_name} not applicable')


