def _poly_add(p1: Polynomial, p2: Polynomial) -> Polynomial:
    result = dict(p1)
    for mono, coeff in p2.items():
        result[mono] = result.get(mono, 0) + coeff
    return {k: v for k, v in result.items() if v != 0}


