def _poly_mul(p1: Polynomial, p2: Polynomial) -> Polynomial:
    result: Polynomial = {}
    for m1, c1 in p1.items():
        for m2, c2 in p2.items():
            m = _mono_mul(m1, m2)
            result[m] = result.get(m, 0) + c1 * c2
    return {k: v for k, v in result.items() if v != 0}


