def _mono_mul(m1: Monomial, m2: Monomial) -> Monomial:
    vars_dict: Dict[str, int] = {}
    for name, exp in m1:
        vars_dict[name] = vars_dict.get(name, 0) + exp
    for name, exp in m2:
        vars_dict[name] = vars_dict.get(name, 0) + exp
    return tuple(sorted(vars_dict.items()))


