# ║ Path(build_chain(ste), build a rewritechain from a list of (intermediate, proof) pairs) over List[Tuple[OTerm, ProofTerm]] ║
# ╠════════════════════════════════════════════════════════════╣
# ║ build_chain : List[Tuple[OTerm, ProofTerm]] → ProofTerm    ║
# ╠════════════════════════════════════════════════════════════╣
