# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.tactics.build_chain","kind":"function","src_hash":"f5e5f5b74986f3b0","in":{"base":"List[Tuple[OTerm, ProofTerm]]"},"out":{"base":"ProofTerm"},"spec":{"lhs":"build_chain(ste)","rhs":"build a rewritechain from a list of (intermediate, proof) pairs","over":{"base":"List[Tuple[OTerm, ProofTerm]]"},"name":"build_chain_correct"},"guarantee":"build a rewritechain from a list of (intermediate, proof) pairs","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.tactics.build_chain_correct","statement":"Path(build_chain(x), build a rewritechain from a list of (intermediate, proof) pairs)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"8a20339edb1d88c1"}
def build_chain(steps: List[Tuple[OTerm, ProofTerm]],
                final: OTerm) -> ProofTerm:
    """Build a RewriteChain from a list of (intermediate, proof) pairs.

    steps = [(a₁, p₁), (a₂, p₂), ...]
    where p₁ : a₀ ≡ a₁, p₂ : a₁ ≡ a₂, etc.
    final is the last term.
    """
    if not steps:
        return Refl(final)

    proofs = [p for _, p in steps]
    intermediates = [steps[0][0]]  # Will be filled during construction

    # Build intermediates list
    terms_list = [steps[0][0]]
    for term, _ in steps:
        terms_list.append(term)
    terms_list.append(final)

    if len(proofs) == 1:
        return proofs[0]

    return RewriteChain(tuple(proofs), tuple(terms_list))


