# ║ Path(build_trans_chain(pro), id) over List[ProofTerm]      ║
# ╠════════════════════════════════════════════════════════════╣
# ║ build_trans_chain : List[ProofTerm] → ProofTerm            ║
# ╠════════════════════════════════════════════════════════════╣
