# ║ 🟢 KERNEL | path_compose | Compiled: ✓ | 54a9426e47d96c88   ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.tactics.build_trans_chain","kind":"function","src_hash":"77c1abca0fcdcf6c","in":{"base":"List[ProofTerm]"},"out":{"base":"ProofTerm"},"spec":{"lhs":"build_trans_chain(pro)","rhs":"build a chain of trans from a list of proofs","over":{"base":"List[ProofTerm]"},"name":"build_trans_chain_correct","kind":"composition"},"guarantee":"build a chain of trans from a list of proofs","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"Refl","by":"library_axiom"},{"fn":"OLit","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"54a9426e47d96c88"}
def build_trans_chain(proofs: List[ProofTerm],
                      intermediates: List[OTerm]) -> ProofTerm:
    """Build a chain of Trans from a list of proofs.

    proofs[i] : intermediates[i] ≡ intermediates[i+1]
    """
    if not proofs:
        return Refl(intermediates[0] if intermediates else OLit(None))

    if len(proofs) == 1:
        return proofs[0]

    # Right-associate the Trans chain
    result = proofs[-1]
    for i in range(len(proofs) - 2, -1, -1):
        mid = intermediates[i + 1] if i + 1 < len(intermediates) else None
        result = Trans(proofs[i], result, middle=mid)

    return result


