# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theory.tactics.verify_auto","kind":"function","src_hash":"4a06775e1aeed824","in":{"base":"OTerm"},"out":{"base":"VerificationResult"},"spec":{"lhs":"verify_auto(lhs)","rhs":"try to automatically prove and verify lhs \u2261 rhs","over":{"base":"OTerm"},"name":"verify_auto_correct"},"guarantee":"try to automatically prove and verify lhs \u2261 rhs","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"cctt.proof_theory","axiom_name":"cctt.proof_theory.proof_theory.tactics.verify_auto_correct","statement":"Path(verify_auto(x), try to automatically prove and verify lhs \u2261 rhs)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"aae25f6bda5d3864"}
def verify_auto(lhs: OTerm, rhs: OTerm,
                ctx: Optional[ProofContext] = None) -> VerificationResult:
    """Try to automatically prove and verify lhs ≡ rhs.

    Combines auto tactic with the checker.  Returns a VerificationResult.
    """
    r = auto(lhs, rhs, ctx)
    if not r.success:
        return VerificationResult(False, f'auto failed: {r.reason}')

    return check_proof(r.proof, lhs, rhs, ctx)


